(function() {
      try {
        // フォロワー数とフォロー数のリンクを探す
        let followerLink = document.querySelector('a[href*="/verified_followers"]');
        let followingLink = document.querySelector('a[href*="/following"]');

        // パターン2: 通常のfollowers/followingリンク
        if (!followerLink) {
          followerLink = document.querySelector('a[href*="/followers"]');
        }
        if (!followingLink) {
          followingLink = document.querySelector('a[href*="/following"]');
        }

        // パターン3: プロフィールヘッダー内を探す
        const profileHeader = document.querySelector('[data-testid="UserProfileHeader_Items"]') || 
                             document.querySelector('[data-testid="UserName"]')?.closest('div')?.parentElement;

        if (profileHeader) {
          if (!followerLink) {
            followerLink = profileHeader.querySelector('a[href*="/followers"], a[href*="/verified_followers"]');
          }
          if (!followingLink) {
            followingLink = profileHeader.querySelector('a[href*="/following"]');
          }
        }

        let followerCount = null;
        let followingCount = null;

        // フォロワー数を取得
        if (followerLink) {
          const linkText = followerLink.textContent || followerLink.innerText || '';
          // 数値とカンマを含むパターンを探す（例: "1" や "1,234"）
          const match = linkText.match(/([\d,]+)/);
          if (match) {
            followerCount = parseInt(match[1].replace(/,/g, ''), 10);
          }
        }

        // フォロー数を取得
        if (followingLink) {
          const linkText = followingLink.textContent || followingLink.innerText || '';
          // 数値とカンマを含むパターンを探す（例: "5" や "5,678"）
          const match = linkText.match(/([\d,]+)/);
          if (match) {
            followingCount = parseInt(match[1].replace(/,/g, ''), 10);
          }
        }

        // パターン4: プロフィールヘッダー内のテキストから直接取得
        if (profileHeader && (followerCount === null || followingCount === null)) {
          const headerText = profileHeader.textContent || '';
          // フォロワー数を探す
          if (followerCount === null) {
            const followerMatch = headerText.match(/([\d,]+)\s*(フォロワー|Followers|follower)/i);
            if (followerMatch) {
              followerCount = parseInt(followerMatch[1].replace(/,/g, ''), 10);
            }
          }
          // フォロー数を探す
          if (followingCount === null) {
            const followingMatch = headerText.match(/([\d,]+)\s*(フォロー|Following)/i);
            if (followingMatch) {
              followingCount = parseInt(followingMatch[1].replace(/,/g, ''), 10);
            }
          }
        }

        if (followerCount !== null || followingCount !== null) {
          return { 
            ok: true, 
            followerCount: followerCount,
            followingCount: followingCount,
            didAction: true,
            reason: 'フォロワー数: ' + (followerCount !== null ? followerCount : '取得失敗') + ', フォロー数: ' + (followingCount !== null ? followingCount : '取得失敗')
          };
        }

        return { 
          ok: false, 
          error: 'フォロワー数またはフォロー数が見つかりませんでした',
          didAction: false
        };
      } catch (e) {
        return {
          ok: false,
          error: 'エラーが発生しました: ' + (e.message || String(e)),
          didAction: false
        };
      }
    })()

(async () => {
  const searchCount = { found: 0, skipped: 0, error: 0 };
  let targetUsername = null;
  let statusUrl = null;
  const maxScrollAttempts = 10;
  const debugInfo = []; // Collect debug information

  async function isFollowingByHover(article, timeoutMs = 3000) {
    // 非アクティブ時は処理をスキップ
    if (document.hidden || document.visibilityState === 'hidden') {
      return { result: null, reason: "window is inactive/hidden, skipping hover check" };
    }
    try {
      // ユーザー名リンク取得
      const userNameEl = article.querySelector('[data-testid="User-Name"]');
      if (!userNameEl) {
        return { result: null, reason: "User-Name element not found" };
      }

      const link = userNameEl.querySelector('a[href^="/"]') || userNameEl.closest('a[href^="/"]');
      if (!link) {
        return { result: null, reason: "user link not found" };
      }

      // リンクが表示されるようにスクロール
      // 非アクティブ時でも動作するように直接スクロール位置を設定
      const rect = link.getBoundingClientRect();
      const scrollY = window.scrollY + rect.top - window.innerHeight / 2;
      window.scrollTo({ top: scrollY, behavior: 'smooth' });
      await new Promise(r => setTimeout(r, 500)); // スクロール完了を待つ（時間を延長）

      // マウス位置をリンク中央に設定（上で取得したrectを再利用）
      const x = rect.left + rect.width / 2;
      const y = rect.top + rect.height / 2;

      // より詳細なイベント設定
      const eventInit = {
        bubbles: true,
        cancelable: true,
        clientX: x,
        clientY: y,
        screenX: x + window.screenX,
        screenY: y + window.screenY,
        view: window,
        detail: 0,
        buttons: 0,
        relatedTarget: null
      };

      // 既存のホバーカードを閉じる（他の要素にホバーしている可能性があるため）
      const existingHoverCard = document.querySelector('[data-testid="HoverCard"]') || document.querySelector('[data-testid*="HoverCard"]');
      if (existingHoverCard) {
        // マウスアウトイベントを発火して既存のホバーカードを閉じる
        existingHoverCard.dispatchEvent(new MouseEvent('mouseout', eventInit));
        await new Promise(r => setTimeout(r, 200));
      }

      // いろいろな種類のイベントを投げてホバーカードを出す
      // 順番が重要：pointer系 → mouse系
      const eventTypes = [
        "pointerover",
        "pointerenter",
        "mouseenter",
        "mouseover",
        "pointermove",
        "mousemove"
      ];

      for (const type of eventTypes) {
        link.dispatchEvent(new MouseEvent(type, eventInit));
        await new Promise(r => setTimeout(r, 50)); // 各イベントの間に少し待機
      }

      // ホバーカードが出てくるまで待つ
      const start = performance.now();
      let hoverCard = null;
      while (performance.now() - start < timeoutMs) {
        // 非アクティブになった場合は待機を短縮
        if (document.hidden || document.visibilityState === 'hidden') {
          timeoutMs = Math.min(timeoutMs, 1000); // 最大1秒に制限
        }
        // data-testid 名は変わる可能性があるので候補をいくつか見る
        hoverCard =
          document.querySelector('[data-testid="HoverCard"]') ||
          document.querySelector('[data-testid*="HoverCard"]') ||
          document.querySelector('[role="dialog"] [data-testid="UserName"]')?.closest('[role="dialog"]') ||
          document.querySelector('[data-testid="UserCell"]')?.closest('[role="dialog"]');
        if (hoverCard) break;
        await new Promise((r) => setTimeout(r, 100)); // 待機間隔を延長
      }

      if (!hoverCard) {
        // ホバーカードが出なかった場合
        return { result: null, reason: "hover card not found after timeout" };
      }

      // ホバーカードが表示された後、3秒待機（動きをわかりやすくするため）
      await new Promise(r => setTimeout(r, 1000));

      // ホバーカード内のフォローボタンを探す（より広範囲に検索）
      const followBtn =
        hoverCard.querySelector('button[data-testid*="follow"]') ||
        hoverCard.querySelector('button[data-testid$="-follow"]') ||
        hoverCard.querySelector('button[data-testid="follow"]') ||
        hoverCard.querySelector('button[aria-label*="フォロー"]') ||
        hoverCard.querySelector('button[aria-label*="Follow"]') ||
        hoverCard.querySelector('button[aria-label*="Following"]') ||
        hoverCard.querySelector('button[aria-label*="Unfollow"]');

      if (!followBtn) {
        return { result: null, reason: "follow button not found in hover card" };
      }

      const text = (followBtn.textContent || "").trim();
      const aria = (followBtn.getAttribute("aria-label") || "").trim();
      const testId = (followBtn.getAttribute("data-testid") || "").trim();
      const label = (text + " " + aria + " " + testId).toLowerCase();

      // 「フォロー中 / フォロー解除 / Following / Unfollow」をフォロー済みとみなす
      if (
        label.includes("フォロー中") ||
        label.includes("フォロー解除") ||
        label.includes("following") ||
        label.includes("unfollow") ||
        testId.includes("unfollow")
      ) {
        return { result: true, reason: `following detected: text=${text}, aria=${aria}, testid=${testId}` };
      }

      // 「フォロー / Follow」が入っていれば未フォローとみなす
      if (label.includes("フォロー") || label.includes("follow")) {
        return { result: false, reason: `not following: text=${text}, aria=${aria}, testid=${testId}` };
      }

      // どちらとも判定できなかった
      return { result: null, reason: `cannot determine follow status: text=${text}, aria=${aria}, testid=${testId}` };
    } catch (e) {
      return { result: null, reason: `error: ${e.message}` };
    }
  }

  async function checkArticle(article) {
    try {
      // Check if this is a promoted/advertisement post
      // Reference: isPromotion function from other presets
      if (!article) return null;

      // Check for aria-label="プロモーション"
      if (article.querySelector('[aria-label="プロモーション"]')) {
        return { skipped: true, reason: "promoted/advertisement post (aria-label)" };
      }

      // Check for data-testid="placementTracking" (including parent elements)
      if (article.querySelector('[data-testid="placementTracking"]') || article.closest('[data-testid="placementTracking"]')) {
        return { skipped: true, reason: "promoted/advertisement post (placementTracking)" };
      }

      // Check for badge with "プロモーション" text
      const badge = article.querySelector('[role="button"][data-testid="userActions"] ~ div span');
      if (badge && badge.textContent && badge.textContent.includes('プロモーション')) {
        return { skipped: true, reason: "promoted/advertisement post (badge text)" };
      }

      // Additional checks for English "Promoted" text
      const articleText = article.textContent || article.innerText || "";
      const lowerText = articleText.toLowerCase();
      if (lowerText.includes("promoted") || lowerText.includes("promoted by")) {
        return { skipped: true, reason: "promoted/advertisement post (text content)" };
      }

      // Check for #PR in post text (skip PR posts)
      if (articleText.includes("#PR") || articleText.includes("#pr") || lowerText.includes("#pr")) {
        return { skipped: true, reason: "PR post (contains #PR)" };
      }

      const likeBtn = article.querySelector("[data-testid=\"like\"]");
      const unlikeBtn = article.querySelector("[data-testid=\"unlike\"]");
      if (unlikeBtn) return { skipped: true, reason: "already liked" };
      if (!likeBtn) return { skipped: true, reason: "no like button" };

      const isLiked = likeBtn.getAttribute("aria-pressed") === "true";
      if (isLiked) return { skipped: true, reason: "already liked (aria-pressed)" };

      // プロモーション投稿の場合はフォロー確認をスキップ
      const isPromoted = article.querySelector('[aria-label="プロモーション"]') || 
                        (article.querySelector('[data-testid="placementTracking"]') || article.closest('[data-testid="placementTracking"]')) ||
                        (() => {
                          const badge = article.querySelector('[role="button"][data-testid="userActions"] ~ div span');
                          if (badge && badge.textContent && badge.textContent.includes('プロモーション')) {
                            return true;
                          }
                          const articleText2 = article.textContent || article.innerText || "";
                          // Check for Japanese "プロモーション" text in article
                          if (articleText2.includes("プロモーション")) {
                            return true;
                          }
                          return articleText2.toLowerCase().includes("promoted") || articleText2.toLowerCase().includes("promoted by");
                        })();

            // プロモーション投稿の場合はフォロー確認をスキップ
      let hoverResult = { result: null, reason: "skipped for promoted post" };
      if (!isPromoted) {
        hoverResult = await isFollowingByHover(article, 3000);
      }
      if (hoverResult.result === true) {
        // 既にフォローしているユーザー → スキップ
        return { skipped: true, reason: `already following (hover card): ${hoverResult.reason}` };
      }
      // ホバーカード判定が失敗した場合（null）は、既存のフォロー判定にフォールバック
      // ただし、デバッグ情報として記録
      const hoverDebugInfo = hoverResult.reason ? { hoverCardResult: hoverResult.reason } : null;

      // Check for follow/unfollow buttons more comprehensively
      // Collect all follow-related buttons for debugging
      const followDebugInfo = { foundButtons: [], foundUnfollow: false, reason: null, hoverDebugInfo: hoverDebugInfo };

      // First, check for explicit unfollow buttons with various selectors
      const unfollowSelectors = [
        "[data-testid=\"unfollow\"]",
        "[data-testid$=\"-unfollow\"]",
        "[data-testid*=\"unfollow\"]",
        "button[aria-label*=\"フォロー解除\"]",
        "button[aria-label*=\"Unfollow\"]",
        "button[aria-label*=\"Following\"]"
      ];

      for (const selector of unfollowSelectors) {
        const el = article.querySelector(selector);
        if (el) {
          const testId = el.getAttribute("data-testid") || "";
          const text = (el.textContent || "").trim();
          const ariaLabel = (el.getAttribute("aria-label") || "").trim();
          followDebugInfo.foundUnfollow = true;
          followDebugInfo.reason = `unfollow button found: selector=${selector}, testid=${testId}, text=${text}, aria-label=${ariaLabel}`;
          return { skipped: true, reason: followDebugInfo.reason, debugInfo: followDebugInfo };
        }
      }

      // Check all buttons with "follow" in data-testid
      const allFollowButtons = article.querySelectorAll("[data-testid*=\"follow\"]");
      for (const btn of allFollowButtons) {
        const testId = btn.getAttribute("data-testid") || "";
        const btnText = (btn.textContent || btn.innerText || "").trim();
        const ariaLabel = (btn.getAttribute("aria-label") || "").trim();
        const combinedText = `${btnText} ${ariaLabel}`.toLowerCase();

        followDebugInfo.foundButtons.push({ testId, btnText, ariaLabel, combinedText });

        // If data-testid contains "unfollow", skip
        if (testId.includes("unfollow") || testId.endsWith("-unfollow")) {
          followDebugInfo.reason = `unfollow in testid: ${testId}`;
          return { skipped: true, reason: followDebugInfo.reason, debugInfo: followDebugInfo };
        }

        // Check for following indicators (case-insensitive)
        if (combinedText.includes("following") || 
            combinedText.includes("フォロー中") || 
            combinedText.includes("フォロー解除") ||
            combinedText.includes("unfollow") ||
            btnText === "Following" ||
            btnText === "フォロー中") {
          followDebugInfo.reason = `following indicator in text: btnText=${btnText}, ariaLabel=${ariaLabel}`;
          return { skipped: true, reason: followDebugInfo.reason, debugInfo: followDebugInfo };
        }
      }

      // Also check for buttons with aria-label containing follow-related text
      const ariaLabelButtons = article.querySelectorAll("[aria-label*=\"フォロー\"], [aria-label*=\"Follow\"]");
      for (const btn of ariaLabelButtons) {
        const ariaLabel = (btn.getAttribute("aria-label") || "").trim().toLowerCase();
        const testId = btn.getAttribute("data-testid") || "";
        const btnText = (btn.textContent || "").trim();

        if (ariaLabel.includes("フォロー中") || 
            ariaLabel.includes("フォロー解除") ||
            ariaLabel.includes("unfollow") ||
            ariaLabel.includes("following")) {
          followDebugInfo.reason = `following in aria-label: ${ariaLabel}, testid=${testId}, text=${btnText}`;
          return { skipped: true, reason: followDebugInfo.reason, debugInfo: followDebugInfo };
        }
      }

      // Check for any button that might indicate following state
      // Look for buttons with specific text patterns
      const allButtons = article.querySelectorAll("button, [role=\"button\"]");
      for (const btn of allButtons) {
        const btnText = (btn.textContent || btn.innerText || "").trim();
        const ariaLabel = (btn.getAttribute("aria-label") || "").trim();
        const testId = btn.getAttribute("data-testid") || "";

        // Check if button text indicates following state
        if (btnText === "Following" || btnText === "フォロー中" || btnText === "フォロー解除") {
          followDebugInfo.reason = `following button text found: ${btnText}, testid=${testId}, aria-label=${ariaLabel}`;
          return { skipped: true, reason: followDebugInfo.reason, debugInfo: followDebugInfo };
        }

        // Check aria-label for following indicators
        if (ariaLabel && (ariaLabel.includes("フォロー中") || ariaLabel.includes("フォロー解除") || ariaLabel.toLowerCase().includes("unfollow") || ariaLabel.toLowerCase().includes("following"))) {
          followDebugInfo.reason = `following in button aria-label: ${ariaLabel}, testid=${testId}, text=${btnText}`;
          return { skipped: true, reason: followDebugInfo.reason, debugInfo: followDebugInfo };
        }
      }

      let username = null;
      const userNameEl = article.querySelector("[data-testid=\"User-Name\"]");
      if (userNameEl) {
        const userLink = userNameEl.querySelector("a[href^=\"/\"]") || userNameEl.closest("div")?.querySelector("a[href^=\"/\"]");
        if (userLink) {
          const href = userLink.getAttribute("href");
          const match = href.match(/^\/([^\/\?]+)/);
          if (match && match[1] && !match[1].includes("status") && !match[1].includes("hashtag")) {
            username = match[1];
          }
        }
      }
      if (!username) {
        const userLinks = article.querySelectorAll("a[href^=\"/\"]");
        for (const link of userLinks) {
          const href = link.getAttribute("href");
          const text = link.textContent || "";
          if (href && href.startsWith("/") && !href.includes("/status/") && !href.includes("/hashtag/") && !href.includes("/search") && !href.includes("/i/") && !href.includes("/explore") && !href.includes("/photo/") && !href.includes("/video/") && !href.includes("/analytics")) {
            const match = href.match(/^\/([^\/\?]+)/);
            if (match && match[1] && match[1].length > 0 && (text.includes("@") || /^[a-zA-Z0-9_]+$/.test(match[1]))) {
              username = match[1];
              break;
            }
          }
        }
      }
      const statusLink = article.querySelector("a[href*=\"/status/\"]");
      if (!statusLink) return null;
      const href = statusLink.getAttribute("href");
      if (!href || !href.includes("/status/")) return null;
      const url = href.startsWith("http") ? href : `https://x.com${href}`;

      if (username && url) {
        return { username, statusUrl: url, statusLink, article };
      }
      return null;
    } catch (e) {
      searchCount.error++;
      return null;
    }
  }

  async function searchPosts() {
    // 非アクティブ検出
    const isInactive = document.hidden || document.visibilityState === 'hidden';
    if (isInactive) {
      console.warn('Window is inactive/hidden, some operations may be delayed');
    }
    const processedArticleIds = new Set();
    const skipReasons = []; // Collect skip reasons for debugging
    const candidates = []; // Collect all valid posts
    const targetCandidates = 10; // Stop when we find 10 candidates

    let scrollAttempts = 0;
    const maxScrollAttempts = 10; // Maximum scroll attempts

    while (scrollAttempts < maxScrollAttempts && candidates.length < targetCandidates) {
      // Get all articles currently visible
      const articles = Array.from(document.querySelectorAll("article"));

      // Process each article
      for (const article of articles) {
        // Stop if we have enough candidates
        if (candidates.length >= targetCandidates) break;

        const statusLink = article.querySelector("a[href*=\"/status/\"]");
        let articleId = null;
        if (statusLink) {
          const href = statusLink.getAttribute("href");
          if (href) {
            articleId = href.includes("/status/") ? href : null;
          }
        }
        if (!articleId) {
          articleId = article.getAttribute("data-testid") || article.id || article.textContent?.slice(0, 50) || Math.random().toString();
        }
        if (processedArticleIds.has(articleId)) continue;
        processedArticleIds.add(articleId);

        const result = await checkArticle(article);
        // Collect valid posts instead of clicking immediately
        if (result && result.username && result.statusUrl) {
          searchCount.found++;
          candidates.push({
            username: result.username,
            statusUrl: result.statusUrl,
            statusLink: result.statusLink,
            article: result.article
          });
        } else {
          searchCount.skipped++;
          if (result && result.skipped) {
            skipReasons.push({ articleId, reason: result.reason, debugInfo: result.debugInfo });
          } else {
            skipReasons.push({ articleId, reason: "unknown skip reason" });
          }
        }
      }

      // Stop if we have enough candidates
      if (candidates.length >= targetCandidates) break;

      // Scroll down to load more posts
      scrollAttempts++;
      if (scrollAttempts < maxScrollAttempts) {
        window.scrollBy(0, 500);
        await new Promise(r => setTimeout(r, 1000)); // Wait for new content to load
      }
    }

    // If no candidates found, return early
    if (candidates.length === 0) {
      return { skipReasons: skipReasons };
    }

    // Randomly select one candidate
    const selected = candidates[Math.floor(Math.random() * candidates.length)];

    // Scroll to the selected post and click
    // 非アクティブ時でも動作するように直接スクロール位置を設定
      const articleRect = selected.article.getBoundingClientRect();
      const scrollY = window.scrollY + articleRect.top - window.innerHeight / 2;
      window.scrollTo({ top: scrollY, behavior: 'smooth' });
    await new Promise(r => setTimeout(r, 1000));

    window.__targetUsername = selected.username;
    window.__targetStatusUrl = selected.statusUrl;
    const targetArticle = selected.article;
    selected.statusLink.click();

    let waitCount = 0;
    const maxWaitCount = 40;
    while (waitCount < maxWaitCount) {
      if (!targetArticle.isConnected) {
        return { didAction: true, reason: `found and navigated to target post (selected from ${candidates.length} candidates)`, stats: searchCount, username: selected.username, statusUrl: selected.statusUrl, skipReasons: skipReasons };
      }
      await new Promise(r => setTimeout(r, 500));
      waitCount++;
    }

    return { didAction: false, reason: "article element did not disappear after click", skipReasons: skipReasons };
  }

  let result = await searchPosts();
  if (result && result.username && result.statusUrl) return result;

  return { didAction: false, reason: `no suitable post found`, stats: searchCount, skipReasons: result?.skipReasons || [] };
})()

(async () => {
    // 非アクティブ検出
    const isInactive = document.hidden || document.visibilityState === 'hidden';
    if (isInactive) {
      console.warn('Window is inactive/hidden, reply operations may be delayed');
    }

    // いいねボタンを探す関数（スクロール対応）
    async function findLikeButton(maxScrollAttempts = 5) {
      let scrollAttempts = 0;

      while (scrollAttempts < maxScrollAttempts) {
        let likeBtn = null;
        let unlikeBtn = null;
        const article = document.querySelector("article");

        // まずarticle内を探す
        if (article) {
          likeBtn = article.querySelector("[data-testid=\"like\"]");
          unlikeBtn = article.querySelector("[data-testid=\"unlike\"]");
        }

        // 見つからない場合は全体を探す
        if (!likeBtn && !unlikeBtn) {
          likeBtn = document.querySelector("[data-testid=\"like\"]");
          unlikeBtn = document.querySelector("[data-testid=\"unlike\"]");
        }

        // 既にいいね済みの場合は終了
        if (unlikeBtn) {
          return { likeBtn: null, unlikeBtn, alreadyLiked: true };
        }

        // いいねボタンが見つかった場合
        if (likeBtn) {
          // ボタンが表示されているか確認
          const rect = likeBtn.getBoundingClientRect();
          const isVisible = rect.width > 0 && rect.height > 0 && 
                           rect.top >= 0 && rect.left >= 0 &&
                           rect.bottom <= window.innerHeight && 
                           rect.right <= window.innerWidth;

          if (isVisible) {
            return { likeBtn, unlikeBtn: null, alreadyLiked: false };
          } else {
            // ボタンが画面外にある場合、スクロール
            const scrollY = window.scrollY + rect.top - window.innerHeight / 2;
            window.scrollTo({ top: scrollY, behavior: 'smooth' });
            await new Promise(r => setTimeout(r, 500));
          }
        } else {
          // いいねボタンが見つからない場合、少しスクロールして再試行
          if (scrollAttempts < maxScrollAttempts - 1) {
            window.scrollBy(0, 300);
            await new Promise(r => setTimeout(r, 500));
          }
        }

        scrollAttempts++;
      }

      return { likeBtn: null, unlikeBtn: null, alreadyLiked: false };
    }

    // いいねボタンを探す
    const { likeBtn, unlikeBtn, alreadyLiked } = await findLikeButton(5);

    if (alreadyLiked) {
      return { didAction: false, reason: "already liked" };
    }

    if (!likeBtn) {
      return { didAction: false, reason: "like button not found after scrolling" };
    }

    // いいねボタンをクリック
    likeBtn.click();

    // 待機時間を延長（非アクティブ時も最低1秒）
    const waitTime = isInactive ? 1000 : 1500;
    await new Promise(r => setTimeout(r, waitTime));

    // いいねが反映されたか確認（複数回確認）
    const article = document.querySelector("article");
    let unlikeBtnAfter = null;
    let checkAttempts = 0;
    const maxCheckAttempts = 5;

    while (checkAttempts < maxCheckAttempts && !unlikeBtnAfter) {
      unlikeBtnAfter = article 
        ? article.querySelector("[data-testid=\"unlike\"]") 
        : document.querySelector("[data-testid=\"unlike\"]");

      if (!unlikeBtnAfter) {
        await new Promise(r => setTimeout(r, 300));
        checkAttempts++;
      }
    }

    if (!unlikeBtnAfter) {
      return { didAction: false, reason: "like failed - unlike button not found after click" };
    }

    return { didAction: true, reason: "liked the post" };
  })()

(async () => {
  function generateFromSpin(spinText) {
    const choices = spinText.split("|").map(s => s.trim());
    return choices[Math.floor(Math.random() * choices.length)];
  }
  const spinText = "初めまして🌿|初めまして🌸|初めまして💐|初めまして🌼|初めまして🌷|はじめまして🌿|はじめまして🌸|はじめまして💐|はじめまして🌼|はじめまして🌷";
  const replyText = generateFromSpin(spinText);
  const article = document.querySelector("article");
  if (!article) { return { didAction: false, reason: "no article found" }; }
  const replyBtn = article.querySelector("[data-testid=\"reply\"]");
  if (!replyBtn) { return { didAction: false, reason: "reply button not found" }; }
  replyBtn.click();
  await new Promise(r => setTimeout(r, 3000));
  const replyTextarea = document.querySelector("[data-testid=\"tweetTextarea_0\"]");
  if (!replyTextarea) { return { didAction: false, reason: "reply textarea not found" }; }
  replyTextarea.focus();
  replyTextarea.click();
  await new Promise(r => setTimeout(r, 500));
  const range = document.createRange();
  const sel = window.getSelection();
  range.selectNodeContents(replyTextarea);
  range.collapse(false);
  sel.removeAllRanges();
  sel.addRange(range);
  await new Promise(r => setTimeout(r, 200));
  for (let i = 0; i < replyText.length; i++) {
    const char = replyText[i];
    replyTextarea.dispatchEvent(new KeyboardEvent("keydown", { bubbles: true, cancelable: true, key: char, code: char.charCodeAt(0) }));
    replyTextarea.dispatchEvent(new KeyboardEvent("keypress", { bubbles: true, cancelable: true, key: char, code: char.charCodeAt(0) }));
    if (document.execCommand) {
      document.execCommand("insertText", false, char);
    } else {
      const textNode = document.createTextNode(char);
      const range = sel.getRangeAt(0);
      range.insertNode(textNode);
      range.setStartAfter(textNode);
      range.collapse(true);
      sel.removeAllRanges();
      sel.addRange(range);
    }
    replyTextarea.dispatchEvent(new KeyboardEvent("keyup", { bubbles: true, cancelable: true, key: char, code: char.charCodeAt(0) }));
    replyTextarea.dispatchEvent(new Event("input", { bubbles: true, cancelable: true }));
    await new Promise(r => setTimeout(r, 10));
  }
  await new Promise(r => setTimeout(r, 500));
  replyTextarea.dispatchEvent(new Event("input", { bubbles: true, cancelable: true }));
  replyTextarea.dispatchEvent(new Event("change", { bubbles: true, cancelable: true }));
  await new Promise(r => setTimeout(r, 1000));
  let sendBtn = document.querySelector("[data-testid=\"tweetButton\"]");
  if (!sendBtn) { return { didAction: false, reason: "send button not found" }; }
  let waitCount = 0;
  while ((sendBtn.disabled || sendBtn.getAttribute("aria-disabled") === "true") && waitCount < 15) {
    await new Promise(r => setTimeout(r, 300));
    sendBtn = document.querySelector("[data-testid=\"tweetButton\"]");
    if (!sendBtn) { return { didAction: false, reason: "send button disappeared" }; }
    waitCount++;
  }
  if (sendBtn.disabled || sendBtn.getAttribute("aria-disabled") === "true") { return { didAction: false, reason: "send button still disabled after waiting" }; }
  sendBtn.click();
  await new Promise(r => setTimeout(r, 3000));
  const modalDialog = document.querySelector('[role="dialog"]');
  if (modalDialog) {
    const modalTextarea = modalDialog.querySelector("[data-testid=\"tweetTextarea_0\"]");
    if (modalTextarea) { return { didAction: false, reason: "modal did not close after sending reply" }; }
  }
  return { didAction: true, reason: "reply sent", replyText: replyText };
})()

(async () => {
  let targetUsername = window.__targetUsername;
  if (!targetUsername) {
    const urlMatch = window.location.pathname.match(/^\/([^\/]+)\/status\//);
    if (urlMatch && urlMatch[1]) {
      targetUsername = urlMatch[1];
    }
  }
  if (!targetUsername) {
    const article = document.querySelector("article");
    if (article) {
      const userNameEl = article.querySelector("[data-testid=\"User-Name\"]");
      if (userNameEl) {
        const userLink = userNameEl.querySelector("a[href^=\"/\"]") || userNameEl.closest("div")?.querySelector("a[href^=\"/\"]");
        if (userLink) {
          const href = userLink.getAttribute("href");
          const match = href.match(/^\/([^\/\?]+)/);
          if (match && match[1] && !match[1].includes("status") && !match[1].includes("hashtag")) {
            targetUsername = match[1];
          }
        }
      }
      if (!targetUsername) {
        const userLinks = article.querySelectorAll("a[href^=\"/\"]");
        for (const link of userLinks) {
          const href = link.getAttribute("href");
          const text = link.textContent || "";
          if (href && href.startsWith("/") && !href.includes("/status/") && !href.includes("/hashtag/") && !href.includes("/search") && !href.includes("/i/") && !href.includes("/explore") && !href.includes("/photo/") && !href.includes("/video/") && !href.includes("/analytics")) {
            const match = href.match(/^\/([^\/\?]+)/);
            if (match && match[1] && match[1].length > 0 && (text.includes("@") || /^[a-zA-Z0-9_]+$/.test(match[1]))) {
              targetUsername = match[1];
              break;
            }
          }
        }
      }
    }
  }
  if (!targetUsername) { return { didAction: false, reason: "target username not found" }; }
  window.location.href = `https://x.com/${targetUsername}`;
  return { didAction: true, reason: `navigated to profile page`, username: targetUsername };
})()

(async () => {
  let followBtn = document.querySelector("[data-testid$=\"-follow\"]") || document.querySelector("[data-testid=\"follow\"]") || document.querySelector("[aria-label*=\"フォロー\"]");
  if (!followBtn) {
    let waitCount = 0;
    while (!followBtn && waitCount < 15) {
      await new Promise(r => setTimeout(r, 500));
      followBtn = document.querySelector("[data-testid$=\"-follow\"]") || document.querySelector("[data-testid=\"follow\"]") || document.querySelector("[aria-label*=\"フォロー\"]");
      waitCount++;
    }
  }
  if (!followBtn) { return { didAction: false, reason: "follow button not found after navigation" }; }

  // クリック前の状態を保存
  const beforeText = followBtn.textContent || followBtn.innerText || "";
  const beforeAriaLabel = followBtn.getAttribute("aria-label") || "";
  const beforeDataTestId = followBtn.getAttribute("data-testid") || "";

  const btnText = beforeText + " " + beforeAriaLabel;

  // 既にフォロー中の場合はスキップ
  if (btnText.includes("フォロー中") || btnText.includes("Following")) {
    return { didAction: false, reason: "already following" };
  }

  // フォローボタンが見つかった場合のみクリック
  if (btnText.includes("Follow") || btnText.includes("フォロー")) {
    followBtn.click();

    // クリック後の待機（要素が変わるまで待つ）
    await new Promise(r => setTimeout(r, 2000));

    // クリック後の状態を確認
    let afterBtn = document.querySelector("[data-testid$=\"-unfollow\"]") || 
                   document.querySelector("[data-testid$=\"-follow\"]") || 
                   document.querySelector("[data-testid=\"follow\"]") || 
                   document.querySelector("[aria-label*=\"フォロー\"]");

    if (!afterBtn) {
      // ボタンが見つからない場合は少し待って再試行
      await new Promise(r => setTimeout(r, 1000));
      afterBtn = document.querySelector("[data-testid$=\"-unfollow\"]") || 
                 document.querySelector("[data-testid$=\"-follow\"]") || 
                 document.querySelector("[data-testid=\"follow\"]") || 
                 document.querySelector("[aria-label*=\"フォロー\"]");
    }

    if (!afterBtn) {
      return { didAction: false, reason: "follow button disappeared after click (possibly failed)" };
    }

    // クリック後のテキストを取得
    const afterText = afterBtn.textContent || afterBtn.innerText || "";
    const afterAriaLabel = afterBtn.getAttribute("aria-label") || "";
    const afterDataTestId = afterBtn.getAttribute("data-testid") || "";
    const afterBtnText = afterText + " " + afterAriaLabel;

    // 要素が変わったか確認（"Follow" → "Following" または "フォロー" → "フォロー中"）
    const textChanged = (
      (beforeText.includes("Follow") && !beforeText.includes("Following") && afterText.includes("Following")) ||
      (beforeText.includes("フォロー") && !beforeText.includes("フォロー中") && afterText.includes("フォロー中")) ||
      (beforeAriaLabel.includes("Follow") && !beforeAriaLabel.includes("Following") && afterAriaLabel.includes("Following")) ||
      (beforeAriaLabel.includes("フォロー") && !beforeAriaLabel.includes("フォロー中") && afterAriaLabel.includes("フォロー中")) ||
      (beforeDataTestId.endsWith("-follow") && afterDataTestId.endsWith("-unfollow"))
    );

    if (textChanged) {
      return { didAction: true, reason: "followed (text changed from Follow to Following)" };
    } else {
      // 要素が変わらなかった場合は、フォローできなかったと判断
      return { didAction: false, reason: "follow button clicked but text did not change (possibly rate limited or blocked)" };
    }
  }

  return { didAction: false, reason: "button text does not indicate follow action" };
})()
